// Generated by OrchestKit Claude Plugin
// Created: 2026-06-10

/**
 * Unit tests for worktree/worktree-provisioner (#2335).
 *
 * The hook OWNS worktree creation under the current CC contract: it must run
 * `git worktree add` itself and return the absolute path via
 * `hookSpecificOutput.worktreePath` (run-hook.mjs emits it as a bare path for
 * command-type hooks). Side-effects (children-bus, pending marker) happen
 * strictly AFTER successful provisioning — the pre-#2335 order leaked orphan
 * `.worktrees/<name>/children/` shells on every failed spawn.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { execFileSync } from 'node:child_process';
import { existsSync, mkdirSync, mkdtempSync, readFileSync, rmSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import { worktreeProvisioner } from '../../worktree/worktree-provisioner.js';
import { NOOP_CTX } from '../../lib/context.js';

let project: string;

function gitc(...args: string[]): string {
  return execFileSync(
    'git',
    ['-C', project, '-c', 'user.email=t@t', '-c', 'user.name=t', ...args],
    { encoding: 'utf8' },
  );
}

function fire(extra: Record<string, unknown> = {}) {
  return worktreeProvisioner(
    {
      hook_event: 'WorktreeCreate',
      session_id: 's-prov',
      project_dir: project,
      ...extra,
    } as never,
    NOOP_CTX,
  );
}

beforeEach(() => {
  project = mkdtempSync(join(tmpdir(), 'wt-prov-'));
  execFileSync('git', ['init', '--quiet', project], { stdio: 'ignore' });
  writeFileSync(join(project, 'README.md'), 'x');
  gitc('add', '.');
  gitc('commit', '--quiet', '-m', 'init', '--no-gpg-sign');
});

afterEach(() => {
  rmSync(project, { recursive: true, force: true });
});

describe('worktreeProvisioner (#2335)', () => {
  it('provisions a real worktree and returns its path', () => {
    const res = fire({ worktree_name: 'feature-a' });
    const expected = join(project, '.worktrees', 'feature-a');

    expect(res.hookSpecificOutput?.worktreePath).toBe(expected);
    expect(existsSync(join(expected, 'README.md'))).toBe(true);
    expect(gitc('worktree', 'list', '--porcelain')).toContain(expected);
  });

  it('accepts the legacy `name` input field', () => {
    const res = fire({ name: 'legacy-name' });
    expect(res.hookSpecificOutput?.worktreePath).toBe(join(project, '.worktrees', 'legacy-name'));
  });

  it('creates a new branch when `branch` does not exist yet', () => {
    fire({ worktree_name: 'feature-b', branch: 'feat/new-branch' });
    const branches = gitc('branch', '--list', 'feat/new-branch');
    expect(branches).toContain('feat/new-branch');
  });

  it('checks out an existing branch when `branch` exists', () => {
    gitc('branch', 'feat/existing');
    fire({ worktree_name: 'feature-c', branch: 'feat/existing' });
    const head = execFileSync(
      'git',
      ['-C', join(project, '.worktrees', 'feature-c'), 'branch', '--show-current'],
      { encoding: 'utf8' },
    ).trim();
    expect(head).toBe('feat/existing');
  });

  it('provisions detached when `detach` is true', () => {
    fire({ worktree_name: 'feature-d', branch: 'ignored-when-detached', detach: true });
    const porcelain = gitc('worktree', 'list', '--porcelain');
    expect(porcelain).toContain(join(project, '.worktrees', 'feature-d'));
    expect(gitc('branch', '--list', 'ignored-when-detached').trim()).toBe('');
  });

  it('rejects option-smuggling branch values (falls back to detached)', () => {
    fire({ worktree_name: 'feature-e', branch: '--upload-pack=evil' });
    const porcelain = gitc('worktree', 'list', '--porcelain');
    expect(porcelain).toContain(join(project, '.worktrees', 'feature-e'));
    expect(gitc('branch', '--list', '--all').includes('upload-pack')).toBe(false);
  });

  it('writes children-bus + pending marker ONLY after successful creation', () => {
    fire({ worktree_name: 'feature-f' });
    const wt = join(project, '.worktrees', 'feature-f');

    // children-bus lives at <worktree>/.claude/state/children (children-bus.ts)
    expect(existsSync(join(wt, '.claude', 'state', 'children', '.gitkeep'))).toBe(true);
    const marker = join(project, '.claude', 'state', 'worktree-pending', 'feature-f.json');
    expect(existsSync(marker)).toBe(true);
    const parsed = JSON.parse(readFileSync(marker, 'utf8'));
    expect(parsed.parent_sid).toBe('s-prov');
    expect(parsed.worktree_path).toBe(wt);
  });

  it('does NOT leave a shell or marker when provisioning fails', () => {
    // Occupy the target path with real content so `git worktree add` fails
    // and the orphan-shell self-heal refuses to delete it.
    const occupied = join(project, '.worktrees', 'feature-g');
    mkdirSync(occupied, { recursive: true });
    writeFileSync(join(occupied, 'precious.txt'), 'do not delete');

    const res = fire({ worktree_name: 'feature-g' });

    expect(res.hookSpecificOutput?.worktreePath).toBeUndefined();
    expect(existsSync(join(occupied, 'precious.txt'))).toBe(true);
    expect(
      existsSync(join(project, '.claude', 'state', 'worktree-pending', 'feature-g.json')),
    ).toBe(false);
  });

  it('self-heals a pre-#2335 orphan shell at the target path', () => {
    const shell = join(project, '.worktrees', 'feature-h');
    mkdirSync(join(shell, 'children'), { recursive: true });
    writeFileSync(join(shell, 'children', '.gitkeep'), '');

    const res = fire({ worktree_name: 'feature-h' });

    expect(res.hookSpecificOutput?.worktreePath).toBe(shell);
    expect(existsSync(join(shell, 'README.md'))).toBe(true); // real worktree now
  });

  it('is idempotent for an already-registered worktree', () => {
    const first = fire({ worktree_name: 'feature-i' });
    const second = fire({ worktree_name: 'feature-i' });
    expect(second.hookSpecificOutput?.worktreePath).toBe(first.hookSpecificOutput?.worktreePath);
  });

  it('declines (no path) when project_dir is not a git repo', () => {
    const nogit = mkdtempSync(join(tmpdir(), 'wt-nogit-'));
    try {
      const res = worktreeProvisioner(
        { hook_event: 'WorktreeCreate', session_id: 's', project_dir: nogit, worktree_name: 'x' } as never,
        NOOP_CTX,
      );
      expect(res.continue).toBe(true);
      expect(res.hookSpecificOutput?.worktreePath).toBeUndefined();
    } finally {
      rmSync(nogit, { recursive: true, force: true });
    }
  });

  it('honors worktree.sparsePaths from project settings', () => {
    mkdirSync(join(project, 'src'), { recursive: true });
    mkdirSync(join(project, 'docs'), { recursive: true });
    writeFileSync(join(project, 'src', 'a.ts'), 'export {};');
    writeFileSync(join(project, 'docs', 'b.md'), '# b');
    gitc('add', '.');
    gitc('commit', '--quiet', '-m', 'content', '--no-gpg-sign');

    mkdirSync(join(project, '.claude'), { recursive: true });
    writeFileSync(
      join(project, '.claude', 'settings.json'),
      JSON.stringify({ worktree: { sparsePaths: ['src/'] } }),
    );

    const res = fire({ worktree_name: 'feature-sparse' });
    const wt = res.hookSpecificOutput?.worktreePath as string;

    expect(existsSync(join(wt, 'src', 'a.ts'))).toBe(true);
    expect(existsSync(join(wt, 'docs', 'b.md'))).toBe(false);
  });
});
